insert into page_blocks (page_slug, type, title, content, sort_order, published) values
('privatesia', 'collection', 'Legal standard: privatesia', '{"key":"legal_page_privatesia","value":{"sq":{"eyebrow":"Politika e privatësisë","title":"Si i mbron euguide-ks të dhënat, dokumentet dhe përdorimin e AI-së","sub":"Kjo faqe shpjegon çfarë të dhënash përdor platforma, pse përdoren dhe si mbrohen gjatë shfletimit publik, administrimit të përmbajtjes dhe përdorimit të chatbot-it.","back":"Kthehu në fillim","meta":[["Platforma","euguide-ks"],["Qëllimi","informim qytetar për integrimin në BE"],["Përditësuar","maj 2026"]],"notice":"Shfletimi publik i euguide-ks nuk kërkon llogari. Të dhënat personale përdoren vetëm kur janë të nevojshme për siguri, administrim, dërgim të linkut të hyrjes ose funksione të AI-së.","sections":[["Kush jemi","euguide-ks është platformë edukative dhe qytetare për Kosovën, e ndërtuar për të sqaruar integrimin në BE, ligjet, objektivat, raportet dhe burimet zyrtare në një vend të vetëm."],["Çfarë mbledhim","Për vizitorët publikë synojmë të ruajmë minimumin e mundshëm: gjuhën e zgjedhur, kërkimet brenda faqes dhe të dhëna teknike bazë për siguri. Për adminët ruhet emaili, roli dhe historiku minimal i veprimeve."],["Admin dhe magic link","Hyrja në admin bëhet me link në email. Vetëm profilet me rol admin ose editor duhet të kenë qasje. Root admin mbrohet nga fshirja ose degradimi për të ruajtur kontrollin e projektit."],["Chatbot dhe AI","Pyetjet në chatbot mund të përpunohen për të kthyer përgjigje me burime. Përdoruesit nuk duhet të dërgojnë të dhëna shumë personale, dokumente private ose informata që nuk duan të ruhen në histori teknike."],["Dokumentet","Dokumentet e ngarkuara në panelin admin ruhen për kërkim, indeksim, copëzim dhe citim nga AI. Ato duhet të jenë materiale publike, ligje, raporte ose dokumente që projekti ka të drejtë t’i përdorë."],["Palët teknike","Platforma mund të përdorë shërbime si Supabase për databazë/autentikim, Vercel për hostim dhe modele AI për përgjigje. Këto shërbime përdoren vetëm për funksionimin e platformës."],["Ruajtja dhe fshirja","Të dhënat ruhen për aq kohë sa duhen për funksionim, siguri dhe auditim editorial. Përmbajtja, dokumentet dhe profilet mund të fshihen nga adminët e autorizuar, përveç llogarisë root."],["Të drejtat e përdoruesit","Nëse një përdorues kërkon korrigjim ose fshirje të të dhënave që lidhen me të, ekipi i projektit duhet ta trajtojë kërkesën në mënyrë proporcionale dhe të arsyeshme sipas ligjit në fuqi."],["Siguria","Përdoren role, kontroll i qasjes, ruajtje e kufizuar e sekreteve dhe ndarje mes pjesës publike dhe adminit. Asnjë platformë nuk është pa rrezik, prandaj shmanget mbledhja e panevojshme e të dhënave."],["Fëmijët dhe të rinjtë","Përmbajtja është edukative dhe mund të lexohet nga të rinjtë, por nuk kërkohet krijim llogarie nga ta. Materialet ligjore shpjegohen në gjuhë të qartë, pa mbledhje të qëllimshme të të dhënave të fëmijëve."]]},"en":{"eyebrow":"Privacy policy","title":"How euguide-ks protects data, documents and AI use","sub":"This page explains what the platform uses, why it is used and how it is protected while browsing, managing content and using the chatbot.","back":"Back home","meta":[["Platform","euguide-ks"],["Purpose","civic information on EU integration"],["Updated","May 2026"]],"notice":"Public browsing does not require an account. Personal data is used only when necessary for security, administration, login links or AI features.","sections":[["Who we are","euguide-ks is an educational civic platform for Kosovo, built to explain EU integration, laws, objectives, reports and official sources in one place."],["What we collect","For public visitors we keep data minimal: selected language, site searches and basic technical security data. For administrators we store email, role and a minimal action history."],["Admin and magic link","Admin access uses an email login link. Only profiles with admin or editor roles should have access. The root admin is protected from deletion or demotion."],["Chatbot and AI","Chatbot questions may be processed to return sourced answers. Users should not submit sensitive personal data, private documents or information they do not want processed technically."],["Documents","Documents uploaded in the admin panel are stored for search, indexing, chunking and AI citation. They should be public legal materials, reports or files the project may lawfully use."],["Technical providers","The platform may use services such as Supabase for database/auth, Vercel for hosting and AI models for answers. They are used only to operate the platform."],["Retention and deletion","Data is kept only as long as needed for operation, security and editorial audit. Content, documents and profiles may be deleted by authorised admins, except the root account."],["User rights","Requests to correct or delete personal data related to a user should be handled proportionately and reasonably under applicable law."],["Security","The platform uses roles, access checks, limited secret handling and separation between public and admin areas. Since no system is risk-free, unnecessary data collection is avoided."],["Children and youth","The content is educational and may be read by young people, but they are not asked to create accounts. Legal materials are explained clearly without intentional collection of children''s data."]]},"sr":{"eyebrow":"Politika privatnosti","title":"Kako euguide-ks štiti podatke, dokumente i upotrebu AI","sub":"Ova stranica objašnjava koje podatke platforma koristi, zašto ih koristi i kako ih štiti tokom javnog pregleda, administracije sadržaja i korišćenja chatbota.","back":"Nazad na početnu","meta":[["Platforma","euguide-ks"],["Svrha","građansko informisanje o EU integraciji"],["Ažurirano","maj 2026"]],"notice":"Javno pregledanje euguide-ks ne zahteva nalog. Lični podaci se koriste samo kada su potrebni za bezbednost, administraciju, link za prijavu ili AI funkcije.","sections":[["Ko smo","euguide-ks je edukativna građanska platforma za Kosovo, izgrađena da objasni EU integraciju, zakone, ciljeve, izveštaje i zvanične izvore na jednom mestu."],["Šta prikupljamo","Za javne posetioce čuvamo minimum: izabrani jezik, pretrage na sajtu i osnovne tehničke podatke za bezbednost. Za administratore čuvamo email, ulogu i minimalnu istoriju aktivnosti."],["Admin i magic link","Pristup adminu ide preko linka u emailu. Pristup treba da imaju samo profili sa ulogom admin ili editor. Root admin je zaštićen od brisanja ili degradacije."],["Chatbot i AI","Pitanja u chatbotu mogu se obraditi radi odgovora sa izvorima. Korisnici ne treba da šalju osetljive lične podatke, privatne dokumente ili informacije koje ne žele da budu tehnički obrađene."],["Dokumenti","Dokumenti učitani u admin panel čuvaju se za pretragu, indeksiranje, deljenje na delove i AI citiranje. Treba da budu javni pravni materijali, izveštaji ili fajlovi koje projekat sme da koristi."],["Tehnički pružaoci","Platforma može koristiti Supabase za bazu/autentikaciju, Vercel za hosting i AI modele za odgovore. Ti servisi se koriste samo za rad platforme."],["Čuvanje i brisanje","Podaci se čuvaju onoliko dugo koliko je potrebno za rad, bezbednost i urednički audit. Sadržaj, dokumenti i profili mogu se brisati od strane ovlašćenih admina, osim root naloga."],["Prava korisnika","Zahtevi za ispravku ili brisanje ličnih podataka korisnika treba da se obrade proporcionalno i razumno prema važećem pravu."],["Bezbednost","Koriste se uloge, kontrole pristupa, ograničeno rukovanje tajnama i odvajanje javnog i admin dela. Pošto nijedan sistem nije bez rizika, izbegava se nepotrebno prikupljanje podataka."],["Deca i mladi","Sadržaj je edukativan i mogu ga čitati mladi, ali se od njih ne traži nalog. Pravni materijali se objašnjavaju jasno bez namernog prikupljanja podataka dece."]]}}}'::jsonb, 900, true),
('kushtet', 'collection', 'Legal standard: kushtet', '{"key":"legal_page_kushtet","value":{"sq":{"eyebrow":"Kushtet e përdorimit","title":"Rregullat e përdorimit të euguide-ks","sub":"Këto kushte e bëjnë të qartë çfarë është platforma, çfarë nuk është, si duhet të përdoren materialet dhe si trajtohen përgjigjet nga AI.","back":"Kthehu në fillim","meta":[["Statusi","platformë edukative"],["Fokusi","Kosova dhe integrimi në BE"],["Përditësuar","maj 2026"]],"notice":"euguide-ks nuk është institucion publik, zyrë ligjore apo burim zyrtar i vetëm. Për vendime ligjore duhet të verifikohet gjithmonë ligji, akti ose institucioni zyrtar.","sections":[["Qëllimi","Platforma ndihmon qytetarët, studentët, gazetarët dhe organizatat të kuptojnë rrugën e Kosovës drejt BE-së, ligjet kryesore dhe institucionet përgjegjëse."],["Jo këshillë ligjore","Përmbajtja është informuese. Ajo nuk zëvendëson avokatin, institucionin kompetent, gjykatën, Gazetën Zyrtare ose versionin zyrtar të një akti."],["Burimet","Kur është e mundur, materialet lidhen me Gazetën Zyrtare, Kuvendin, Qeverinë, Komisionin Evropian, EUR-Lex, ASK, institucionet e drejtësisë dhe raporte të njohura ndërkombëtare."],["AI dhe verifikimi","Chatboti duhet të japë përgjigje me citime kur ka burime. Përdoruesi duhet të kontrollojë linkun, datën dhe nenin para se ta përdorë përgjigjen për vendime praktike."],["Përdorimi i lejuar","Lejohet shfletimi, kërkimi, citimi i shkurtër dhe përdorimi edukativ i materialeve, duke ruajtur burimin dhe duke mos ndryshuar kuptimin e përmbajtjes."],["Përdorimi i ndaluar","Nuk lejohet ngarkimi i dokumenteve private pa të drejtë, keqpërdorimi i chatbotit, sulmet teknike, spam-i, tentimi për qasje në admin ose publikimi i informatave të rreme si zyrtare."],["Përgjegjësia editoriale","Adminët dhe editorët duhet të përdorin burime të verifikuara, të shënojnë datën/statusin e materialit dhe të korrigjojnë gabimet sapo identifikohen."],["Disponueshmëria","Platforma mund të ndryshojë, ndërpritet për mirëmbajtje ose të ketë kufizime teknike. Synimi është që përmbajtja kryesore të mbetet e qasshme dhe e lexueshme."],["Përgjegjësia","euguide-ks ofron orientim dhe strukturë. Nuk merr përgjegjësi për dëme që vijnë nga përdorimi i gabuar, mosverifikimi i burimit ose interpretimi i pasaktë i një materiali."],["Ndryshimet","Kushtet mund të përditësohen kur ndryshon funksionaliteti, ligji, standardi i burimeve ose mënyra e përdorimit të AI-së në platformë."]]},"en":{"eyebrow":"Terms of use","title":"Rules for using euguide-ks","sub":"These terms clarify what the platform is, what it is not, how materials should be used and how AI answers should be treated.","back":"Back home","meta":[["Status","educational platform"],["Focus","Kosovo and EU integration"],["Updated","May 2026"]],"notice":"euguide-ks is not a public institution, law office or the only official source. Legal decisions should always be checked against the official act or institution.","sections":[["Purpose","The platform helps citizens, students, journalists and organisations understand Kosovo''s EU path, key laws and responsible institutions."],["Not legal advice","Content is informational. It does not replace a lawyer, competent institution, court, Official Gazette or the official version of an act."],["Sources","Where possible, materials link to the Official Gazette, Assembly, Government, European Commission, EUR-Lex, statistics, justice institutions and recognised reports."],["AI and verification","The chatbot should cite sources when available. Users should check the link, date and article before relying on an answer for practical decisions."],["Allowed use","Browsing, searching, short citation and educational use are allowed when the source is preserved and the meaning is not distorted."],["Prohibited use","Do not upload private documents without rights, misuse the chatbot, attack the system, spam, attempt admin access or publish false information as official."],["Editorial responsibility","Admins and editors should use verified sources, mark date/status and correct errors once identified."],["Availability","The platform may change, be interrupted for maintenance or have technical limits. The goal is to keep core content accessible and readable."],["Liability","euguide-ks provides orientation and structure. It is not liable for harm caused by misuse, failure to verify a source or incorrect interpretation."],["Changes","Terms may be updated when features, laws, source standards or AI use in the platform change."]]},"sr":{"eyebrow":"Uslovi korišćenja","title":"Pravila korišćenja euguide-ks","sub":"Ovi uslovi objašnjavaju šta platforma jeste, šta nije, kako se koriste materijali i kako treba tretirati AI odgovore.","back":"Nazad na početnu","meta":[["Status","edukativna platforma"],["Fokus","Kosovo i EU integracija"],["Ažurirano","maj 2026"]],"notice":"euguide-ks nije javna institucija, advokatska kancelarija niti jedini zvanični izvor. Za pravne odluke uvek treba proveriti zvanični akt ili instituciju.","sections":[["Svrha","Platforma pomaže građanima, studentima, novinarima i organizacijama da razumeju put Kosova ka EU, ključne zakone i nadležne institucije."],["Nije pravni savet","Sadržaj je informativan. Ne zamenjuje advokata, nadležnu instituciju, sud, Službeni list ili zvaničnu verziju akta."],["Izvori","Kada je moguće, materijali vode ka Službenom listu, Skupštini, Vladi, Evropskoj komisiji, EUR-Lex, statistici, pravosudnim institucijama i priznatim izveštajima."],["AI i provera","Chatbot treba da navede izvore kada postoje. Korisnik treba da proveri link, datum i član pre oslanjanja na odgovor u praksi."],["Dozvoljena upotreba","Dozvoljeni su pregled, pretraga, kratko citiranje i edukativna upotreba uz očuvanje izvora i bez menjanja smisla."],["Zabranjena upotreba","Nije dozvoljeno učitavanje privatnih dokumenata bez prava, zloupotreba chatbota, napadi na sistem, spam, pokušaj admin pristupa ili predstavljanje netačnih informacija kao zvaničnih."],["Urednička odgovornost","Admini i editori treba da koriste proverene izvore, označe datum/status i isprave greške kada se uoče."],["Dostupnost","Platforma se može menjati, biti prekinuta zbog održavanja ili imati tehnička ograničenja. Cilj je da osnovni sadržaj ostane dostupan i čitljiv."],["Odgovornost","euguide-ks pruža orijentaciju i strukturu. Ne odgovara za štetu nastalu pogrešnom upotrebom, neproveravanjem izvora ili pogrešnim tumačenjem."],["Izmene","Uslovi se mogu ažurirati kada se promene funkcije, zakoni, standardi izvora ili upotreba AI u platformi."]]}}}'::jsonb, 901, true),
('aksesueshmeria', 'collection', 'Legal standard: aksesueshmeria', '{"key":"legal_page_aksesueshmeria","value":{"sq":{"eyebrow":"Aksesueshmëria","title":"Qasje e barabartë në materialet e euguide-ks","sub":"Synimi është që qytetarët, studentët dhe përdoruesit me nevoja të ndryshme të mund të gjejnë, lexojnë dhe kuptojnë materialet pa pengesa të panevojshme.","back":"Kthehu në fillim","meta":[["Synimi","WCAG 2.2 AA"],["Gjuhët","shqip, anglisht, serbisht"],["Përditësuar","maj 2026"]],"notice":"Aksesueshmëria trajtohet si pjesë e produktit, jo si shtesë. Çdo faqe duhet të ketë strukturë të qartë, kontrast të lexueshëm, kërkim dhe navigim të kuptueshëm.","sections":[["Standardi","euguide-ks synon përputhje praktike me WCAG 2.2 AA: tekst i lexueshëm, fokus i dukshëm, strukturë semantike dhe përmbajtje që funksionon në pajisje të ndryshme."],["Navigimi","Faqet përdorin breadcrumb, lidhje të qarta, butona me tekst të kuptueshëm dhe renditje logjike që ndihmon përdoruesin të dijë ku ndodhet."],["Tastiera","Elementet interaktive duhet të jenë të arritshme me tastierë, me fokus të dallueshëm dhe pa kurthe navigimi."],["Lexueshmëria","Tekstet shkruhen në gjuhë të thjeshtë, me ndarje në seksione, kërkim në katalogë dhe shpjegime qytetare për materiale ligjore të rënda."],["Gjuhët","Përmbajtja kryesore duhet të jetë e qasshme në shqip, anglisht dhe serbisht. Përkthimet automatike mund të ndihmojnë, por materialet kryesore duhet të kontrollohen nga editori."],["Dokumentet PDF","Disa burime zyrtare të jashtme mund të jenë PDF të skanuara ose jo plotësisht të aksesueshme. Platforma mundohet t’i shoqërojë me përmbledhje, metadata dhe link të drejtpërdrejtë."],["Kontrasti dhe pajisjet","Dizajni duhet të ruajë kontrast të mjaftueshëm, tekst që nuk mbivendoset dhe paraqitje të mirë në telefon, tablet dhe desktop."],["AI dhe zëri","Funksionet AI ose voice mund të kenë kufizime. Përgjigjet e rëndësishme duhet të shfaqen edhe si tekst i lexueshëm dhe me burim."],["Raportimi i problemit","Kur një përdorues has pengesë, duhet të dërgojë faqen, përshkrimin e problemit, pajisjen/browserin dhe, nëse mundet, një screenshot. Kjo ndihmon korrigjimin e shpejtë."],["Përmirësim i vazhdueshëm","Aksesueshmëria kontrollohet sa herë shtohen faqe, cards, tabela, grafikë ose dokumente të reja."]]},"en":{"eyebrow":"Accessibility","title":"Equal access to euguide-ks materials","sub":"The goal is for citizens, students and users with different needs to find, read and understand materials without unnecessary barriers.","back":"Back home","meta":[["Target","WCAG 2.2 AA"],["Languages","Albanian, English, Serbian"],["Updated","May 2026"]],"notice":"Accessibility is treated as part of the product. Each page should have clear structure, readable contrast, search and understandable navigation.","sections":[["Standard","euguide-ks aims for practical WCAG 2.2 AA alignment: readable text, visible focus, semantic structure and content that works across devices."],["Navigation","Pages use breadcrumbs, clear links, understandable buttons and logical order so users know where they are."],["Keyboard","Interactive elements should be reachable by keyboard with visible focus and no navigation traps."],["Readability","Texts use plain language, sections, catalogue search and citizen-friendly explanations of heavy legal materials."],["Languages","Core content should be available in Albanian, English and Serbian. Automatic translation can help, but core materials should be editor-reviewed."],["PDF documents","Some external official sources may be scanned PDFs or not fully accessible. The platform tries to add summaries, metadata and direct links."],["Contrast and devices","Design should preserve enough contrast, avoid overlapping text and work well on phone, tablet and desktop."],["AI and voice","AI or voice features may have limitations. Important answers should also appear as readable text with a source."],["Reporting issues","Users should report the page, issue description, device/browser and, if possible, a screenshot. This helps quick fixes."],["Continuous improvement","Accessibility is checked whenever pages, cards, tables, charts or documents are added."]]},"sr":{"eyebrow":"Pristupačnost","title":"Jednak pristup materijalima euguide-ks","sub":"Cilj je da građani, studenti i korisnici sa različitim potrebama mogu da pronađu, čitaju i razumeju materijale bez nepotrebnih prepreka.","back":"Nazad na početnu","meta":[["Cilj","WCAG 2.2 AA"],["Jezici","albanski, engleski, srpski"],["Ažurirano","maj 2026"]],"notice":"Pristupačnost je deo proizvoda. Svaka stranica treba da ima jasnu strukturu, čitljiv kontrast, pretragu i razumljivu navigaciju.","sections":[["Standard","euguide-ks teži praktičnom usklađivanju sa WCAG 2.2 AA: čitljiv tekst, vidljiv fokus, semantička struktura i sadržaj koji radi na različitim uređajima."],["Navigacija","Stranice koriste breadcrumbs, jasne linkove, razumljive dugmad i logičan redosled da korisnik zna gde se nalazi."],["Tastatura","Interaktivni elementi treba da budu dostupni tastaturom, sa vidljivim fokusom i bez zamki u navigaciji."],["Čitljivost","Tekstovi koriste jednostavan jezik, sekcije, pretragu kataloga i građanska objašnjenja složenih pravnih materijala."],["Jezici","Osnovni sadržaj treba da bude dostupan na albanskom, engleskom i srpskom. Automatski prevod može pomoći, ali ključni materijali treba da prođu uredničku proveru."],["PDF dokumenti","Neki spoljni zvanični izvori mogu biti skenirani PDF-ovi ili ne potpuno pristupačni. Platforma nastoji da doda sažetke, metapodatke i direktne linkove."],["Kontrast i uređaji","Dizajn treba da čuva dovoljan kontrast, izbegava preklapanje teksta i radi dobro na telefonu, tabletu i desktopu."],["AI i glas","AI ili glasovne funkcije mogu imati ograničenja. Važni odgovori treba da budu prikazani i kao čitljiv tekst sa izvorom."],["Prijava problema","Korisnik treba da pošalje stranicu, opis problema, uređaj/browser i, ako može, screenshot. To pomaže brzoj ispravci."],["Stalno poboljšanje","Pristupačnost se proverava kad god se dodaju stranice, kartice, tabele, grafikoni ili dokumenti."]]}}}'::jsonb, 902, true),
('burimet', 'collection', 'Legal standard: burimet', '{"key":"legal_page_burimet","value":{"sq":{"eyebrow":"Standardi i burimeve","title":"Si i zgjedh, kontrollon dhe citon burimet euguide-ks","sub":"Ky standard tregon hierarkinë e burimeve, mënyrën e citimit dhe rregullat për materiale ligjore, raporte, grafika, objektiva dhe përgjigje nga AI.","back":"Kthehu në fillim","meta":[["Burimi kryesor","institucione zyrtare"],["Rregulli","link + datë + status"],["Përditësuar","maj 2026"]],"notice":"Çdo pretendim i rëndësishëm në euguide-ks duhet të lidhet me burim të kontrollueshëm. Kur burimi është i paqartë, përmbajtja duhet të shënohet si kontekst ose të mos publikohet.","sections":[["Hierarkia e burimeve","Prioritet kanë Gazeta Zyrtare, Kuvendi, Qeveria, ministritë, Komisioni Evropian, EUR-Lex, ASK, Avokati i Popullit, AKK, KGJK, KPK dhe institucionet përkatëse."],["Burime ndërkombëtare","Përdoren raportet e Komisionit Evropian, SIGMA/OECD, Bankës Botërore, Transparency International, Freedom House, Reporterëve pa Kufij dhe organizatave me metodologji publike."],["Ligjet","Për ligjet përdoret titulli zyrtar, numri, viti, institucioni, linku në Gazetën Zyrtare ose Kuvend dhe, kur ka ndryshime, shënimi se a është akt i konsoliduar apo jo."],["Kushtetuta","Për nenet kushtetuese përdoret numri i nenit, kapitulli, titulli dhe linku në tekstin zyrtar ose në një burim institucional të verifikueshëm."],["Objektivat e BE-së","Për objektivat përdoren dokumente si MSA, PKZMSA, PKAA, raportet e Komisionit Evropian, udhërrëfyesit dhe plan-veprimet me datë/status të qartë."],["Grafikët","Çdo chart duhet të ketë burimin, vitin, metodologjinë ose shënimin shpjegues. Nëse të dhënat janë të përmbledhura, kjo duhet të thuhet qartë."],["Materialet për qytetarë","Kur ligji përkthehet në gjuhë të thjeshtë, ruhet dallimi mes shpjegimit qytetar dhe tekstit zyrtar. Shpjegimi nuk duhet ta ndryshojë kuptimin juridik."],["AI dhe citimet","Chatboti duhet të preferojë përgjigje me citim: ligj, nen, raport, institucion ose link. Pa burim, përgjigjja duhet të trajtohet si orientim i përgjithshëm."],["Kontrolli editorial","Para publikimit kontrollohen linku, institucioni, data, gjuha dhe statusi. Gabimet korrigjohen me prioritet, sidomos kur prekin të drejta, afate ose procedura."],["Transparenca","Nëse një faqe përdor të dhëna nga disa burime, ato duhet të dallohen me badge ose tekst: Gazeta Zyrtare, Komisioni Evropian, Kuvendi, Qeveria, ASK, OIK, AKK ose burim tjetër."]]},"en":{"eyebrow":"Source standard","title":"How euguide-ks selects, checks and cites sources","sub":"This standard explains source hierarchy, citation rules and requirements for laws, reports, charts, objectives and AI answers.","back":"Back home","meta":[["Primary source","official institutions"],["Rule","link + date + status"],["Updated","May 2026"]],"notice":"Every important claim in euguide-ks should connect to a verifiable source. If the source is unclear, the content should be marked as context or not published.","sections":[["Source hierarchy","Priority goes to the Official Gazette, Assembly, Government, ministries, European Commission, EUR-Lex, statistics agency, Ombudsperson, Anti-Corruption Agency and justice institutions."],["International sources","The platform may use European Commission reports, SIGMA/OECD, World Bank, Transparency International, Freedom House, Reporters Without Borders and organisations with public methodology."],["Laws","Law entries should include official title, number, year, institution, link to the Official Gazette or Assembly and, when amended, whether the text is consolidated."],["Constitution","Constitution articles should include article number, chapter, title and a link to the official text or a verifiable institutional source."],["EU objectives","Objectives use documents such as the SAA, national implementation plans, NPAA, European Commission reports, roadmaps and action plans with clear date/status."],["Charts","Each chart should show source, year, methodology or an explanatory note. If values are summarised, that should be clearly stated."],["Citizen materials","When law is explained in plain language, the distinction between citizen explanation and official text is preserved. The explanation must not change legal meaning."],["AI and citations","The chatbot should prefer cited answers: law, article, report, institution or link. Without a source, the answer should be treated as general orientation."],["Editorial checks","Before publishing, editors check the link, institution, date, language and status. Errors are corrected with priority, especially when they affect rights, deadlines or procedures."],["Transparency","If a page uses several sources, they should be visible through badges or text: Official Gazette, European Commission, Assembly, Government, statistics, Ombudsperson or another source."]]},"sr":{"eyebrow":"Standard izvora","title":"Kako euguide-ks bira, proverava i citira izvore","sub":"Ovaj standard objašnjava hijerarhiju izvora, pravila citiranja i zahteve za zakone, izveštaje, grafikone, ciljeve i AI odgovore.","back":"Nazad na početnu","meta":[["Primarni izvor","zvanične institucije"],["Pravilo","link + datum + status"],["Ažurirano","maj 2026"]],"notice":"Svaka važna tvrdnja u euguide-ks treba da bude povezana sa proverljivim izvorom. Ako izvor nije jasan, sadržaj treba označiti kao kontekst ili ga ne objaviti.","sections":[["Hijerarhija izvora","Prioritet imaju Službeni list, Skupština, Vlada, ministarstva, Evropska komisija, EUR-Lex, statistička agencija, Ombudsman, Agencija protiv korupcije i pravosudne institucije."],["Međunarodni izvori","Platforma može koristiti izveštaje Evropske komisije, SIGMA/OECD, Svetske banke, Transparency International, Freedom House, Reportera bez granica i organizacija sa javnom metodologijom."],["Zakoni","Unosi zakona treba da sadrže zvanični naziv, broj, godinu, instituciju, link ka Službenom listu ili Skupštini i, kada ima izmena, da li je tekst konsolidovan."],["Ustav","Članovi Ustava treba da sadrže broj člana, poglavlje, naslov i link ka zvaničnom tekstu ili proverljivom institucionalnom izvoru."],["EU ciljevi","Ciljevi koriste dokumente kao što su SSP, nacionalni planovi sprovođenja, NPAA, izveštaji Evropske komisije, mape puta i akcioni planovi sa jasnim datumom/statusom."],["Grafikoni","Svaki grafikon treba da prikaže izvor, godinu, metodologiju ili objašnjenje. Ako su vrednosti sažete, to mora biti jasno navedeno."],["Materijali za građane","Kada se zakon objašnjava jednostavnim jezikom, čuva se razlika između građanskog objašnjenja i zvaničnog teksta. Objašnjenje ne sme promeniti pravno značenje."],["AI i citati","Chatbot treba da preferira odgovore sa citatom: zakon, član, izveštaj, institucija ili link. Bez izvora odgovor je samo opšta orijentacija."],["Urednička provera","Pre objave proveravaju se link, institucija, datum, jezik i status. Greške se ispravljaju prioritetno, posebno kada utiču na prava, rokove ili procedure."],["Transparentnost","Ako stranica koristi više izvora, oni treba da budu vidljivi kroz oznake ili tekst: Službeni list, Evropska komisija, Skupština, Vlada, statistika, Ombudsman ili drugi izvor."]]}}}'::jsonb, 903, true),
('be', 'collection', 'EU roadmap steps', '{"key":"eu_roadmap_steps","items":[{"step":"01","title_sq":"MSA në fuqi","status_sq":"E plotësuar","body_sq":"Marrëveshja e Stabilizim-Asociimit është baza kontraktuale Kosovë-BE dhe është në fuqi nga 1 prill 2016.","source":"European Commission / SAA","progress":100},{"step":"02","title_sq":"Aplikimi për BE","status_sq":"E plotësuar","body_sq":"Kosova dorëzoi aplikimin për anëtarësim në Bashkimin Evropian në dhjetor 2022.","source":"Council / Kosovo application","progress":100},{"step":"03","title_sq":"Opinion i Komisionit","status_sq":"Në pritje","body_sq":"Këshilli duhet t’i kërkojë Komisionit Evropian opinion për aplikimin. Ky hap kërkon vullnet politik të shteteve anëtare.","source":"EU enlargement procedure","progress":35},{"step":"04","title_sq":"Status kandidat","status_sq":"Në pritje","body_sq":"Statusi kandidat kërkon vendim unanim në Këshill dhe progres të besueshëm në reforma, sundim ligji dhe normalizim rajonal.","source":"Copenhagen criteria","progress":30},{"step":"05","title_sq":"Screening dhe klasterë","status_sq":"Hap i ardhshëm teknik","body_sq":"Pas statusit kandidat, acquis-ja shqyrtohet në klasterë dhe kapituj për të matur harmonizimin ligjor dhe zbatimin praktik.","source":"EU revised enlargement methodology","progress":20},{"step":"06","title_sq":"Traktati i anëtarësimit","status_sq":"Final","body_sq":"Mbyllja e kapitujve dhe ratifikimi nga të gjitha shtetet anëtare janë hapi përfundimtar para anëtarësimit.","source":"EU accession treaty process","progress":5}]}'::jsonb, 114, true),
('be', 'collection', 'EU progress tracker', '{"key":"eu_progress_tracker","items":[{"area_sq":"Sundimi i ligjit","owner_sq":"KGJK, KPK, Ministria e Drejtësisë","status_sq":"Në progres","deadline_sq":"2025-2027","source_sq":"Kosovo Report 2025","progress":35},{"area_sq":"Lufta kundër korrupsionit","owner_sq":"APK, Prokuroria Speciale, Kuvendi","status_sq":"Në progres","deadline_sq":"2025-2028","source_sq":"Strategjia anti-korrupsion / EC","progress":32},{"area_sq":"Administrata publike","owner_sq":"MAPL/MPB, Qeveria, komunat","status_sq":"Në progres","deadline_sq":"2025-2027","source_sq":"SIGMA / EC","progress":45},{"area_sq":"Të drejtat themelore","owner_sq":"Qeveria, Avokati i Popullit, Kuvendi","status_sq":"Në progres","deadline_sq":"2025-2027","source_sq":"EC / Ombudsperson","progress":45},{"area_sq":"Media dhe liria e shprehjes","owner_sq":"KPM, Kuvendi, RTK","status_sq":"Në progres","deadline_sq":"2025-2026","source_sq":"EC / media acquis","progress":40},{"area_sq":"Normalizimi Kosovë-Serbi","owner_sq":"Qeveria, BE facilitator","status_sq":"Kusht politik","deadline_sq":"Vazhdimisht","source_sq":"EU-facilitated dialogue","progress":30},{"area_sq":"Ekonomia e tregut","owner_sq":"MFPT, BQK, ARBK, Autoriteti i Konkurrencës","status_sq":"Në progres","deadline_sq":"2025-2028","source_sq":"EC economic criteria","progress":48}]}'::jsonb, 116, true),
('be', 'collection', 'EU acquis clusters impact', '{"key":"eu_acquis_clusters","items":[{"cluster":"Themelet","chapters":"23, 24, ekonomi, institucione demokratike, administratë publike","citizen_sq":"Gjykata më të pavarura, procedura më të drejta, institucione që përgjigjen dhe të drejta të zbatueshme.","progress":38},{"cluster":"Tregu i brendshëm","chapters":"1, 2, 3, 4, 6, 7, 8, 9, 28","citizen_sq":"Mbrojtje konsumatore, konkurrencë e drejtë, standarde të produkteve dhe shërbime më të sigurta.","progress":42},{"cluster":"Konkurrueshmëria dhe rritja","chapters":"10, 16, 17, 19, 20, 25, 26, 29","citizen_sq":"Ekonomi më formale, arsim më cilësor, taksa më transparente dhe treg pune më i drejtë.","progress":44},{"cluster":"Agjenda e gjelbër dhe lidhshmëria","chapters":"14, 15, 21, 27","citizen_sq":"Ajër më i pastër, energji më e sigurt, transport më i mirë dhe mbrojtje e mjedisit.","progress":34},{"cluster":"Burimet, bujqësia dhe kohezioni","chapters":"11, 12, 13, 22, 33","citizen_sq":"Siguri ushqimore, zhvillim rural, fonde më të menaxhuara dhe statistika më të besueshme.","progress":31},{"cluster":"Marrëdhëniet e jashtme","chapters":"30, 31","citizen_sq":"Përafrim me politikën e jashtme të BE-së, tregti më e qartë dhe partneritet ndërkombëtar.","progress":52}]}'::jsonb, 118, true),
('be', 'collection', 'European Commission recommendations', '{"key":"ec_recommendations","items":[{"pillar_sq":"Drejtësia","recommendation_sq":"Të forcohet llogaridhënia e KGJK/KPK, menaxhimi i rasteve dhe zbatimi i standardeve të integritetit.","source_sq":"Kosovo Report 2025","priority":"High"},{"pillar_sq":"Anti-korrupsioni","recommendation_sq":"Të ketë rezultate më të matshme në rastet e profilit të lartë, deklarim pasurie dhe konflikt interesi.","source_sq":"Kosovo Report 2025","priority":"High"},{"pillar_sq":"Administrata publike","recommendation_sq":"Të rritet rekrutimi meritor, të zvogëlohen ushtruesit e detyrës dhe të racionalizohen agjencitë.","source_sq":"SIGMA / EC","priority":"High"},{"pillar_sq":"Media","recommendation_sq":"Të garantohet pavarësia e rregullatorëve, transparenca e pronësisë dhe financimi i qëndrueshëm i transmetuesit publik.","source_sq":"EC media recommendations","priority":"Medium"},{"pillar_sq":"Të drejtat themelore","recommendation_sq":"Të zbatohet mbrojtja nga diskriminimi, të drejtat e fëmijëve, personave me aftësi të kufizuara dhe komuniteteve.","source_sq":"EC / Ombudsperson","priority":"High"},{"pillar_sq":"Prokurimi publik","recommendation_sq":"Të rritet transparenca, konkurrenca dhe kontrolli i kontratave publike me rrezik të lartë.","source_sq":"EU rule-of-law standards","priority":"High"}]}'::jsonb, 120, true),
('be', 'collection', 'Citizen action cards', '{"key":"citizen_actions","items":[{"title_sq":"Kërko dokument publik","body_sq":"Përdor të drejtën për qasje në dokumente publike për kontrata, vendime, buxhete dhe raporte.","source_sq":"Ligji për Qasje në Dokumente Publike"},{"title_sq":"Raporto korrupsion","body_sq":"Ruaj datën, vendin, dokumentet dhe komunikimet; raporto te APK, prokuroria ose kanale të sigurta këshillimi.","source_sq":"Ligji për sinjalizuesit / APK"},{"title_sq":"Ankohu ndaj administratës","body_sq":"Nëse institucioni nuk përgjigjet ose vendos padrejtësisht, përdor ankesën administrative dhe pastaj mjetet gjyqësore.","source_sq":"Ligji për Procedurën e Përgjithshme Administrative"},{"title_sq":"Kërko ndihmë juridike falas","body_sq":"Për raste sociale, familjare, pronësore ose administrative, kontrollo kriteret për ndihmë juridike falas.","source_sq":"Agjencia për Ndihmë Juridike Falas"}]}'::jsonb, 122, true);
